const names = [
  "Amara Okafor","Liang Chen","Sofia Rossi","Kwame Mensah","Yuki Tanaka","Elena Petrova","Rahul Mehta","Fatima Al-Sayed","Carlos Garcia","Mei Lin",
  "Ingrid Johansson","Tomas Novak","Aisha Bello","Hiroshi Sato","Valentina Cruz","Omar Haddad","Priya Nair","Lucas Silva","Noor Hassan","Chidi Eze",
  "Anya Kowalski","Diego Fernandez","Mariam Khoury","Kenji Watanabe","Isabela Santos","Tariq Aziz","Greta Becker","Sanjay Gupta","Camila Torres","Yusuf Ibrahim",
  "Nadia Rahman","Felix Wagner","Thandiwe Dube","Marco Bianchi","Leila Amari","Stefan Muller","Aiko Suzuki","Pablo Ramirez","Zanele Khumalo","Ravi Shankar",
  "Astrid Larsen","Bashir Diallo","Lucia Moreno","Erik Andersson","Amina Yusuf","Hugo Lefevre","Wei Zhang","Sara Lindqvist","Joaquin Vidal","Grace Adeyemi"
];
const countries = [
  "Nigeria","China","Italy","Ghana","Japan","Russia","India","Egypt","Mexico","Singapore",
  "Sweden","Czech Republic","Nigeria","Japan","Brazil","Lebanon","India","Brazil","Pakistan","Nigeria",
  "Poland","Argentina","Lebanon","Japan","Brazil","Pakistan","Germany","India","Colombia","Nigeria",
  "Bangladesh","Germany","Zimbabwe","Italy","Morocco","Germany","Japan","Spain","South Africa","India",
  "Norway","Senegal","Spain","Sweden","Somalia","France","China","Sweden","Spain","Nigeria"
];
const levelBlocks = [
  { level: "Undergraduate Student" },
  { level: "Master's Student" },
  { level: "PhD Researcher" },
  { level: "Professor" },
  { level: "Industry Professional" }
];
const interestPools = {
  "Undergraduate Student": ["renewable energy systems","intro to machine learning","sustainable urban design","robotics fundamentals","public health policy","data ethics","entrepreneurship in STEM","biomedical devices","climate adaptation","cybersecurity basics"],
  "Master's Student": ["applied NLP","structural engineering resilience","environmental economics","computer vision for diagnostics","supply chain optimization","educational technology","materials science","water resource management","human-computer interaction","financial modeling"],
  "PhD Researcher": ["multi-agent reinforcement learning","quantum materials","epidemiological modeling","computational linguistics","carbon capture chemistry","neural signal processing","urban climate resilience","synthetic biology","distributed systems theory","behavioral economics"],
  "Professor": ["AI governance and policy","large-scale energy systems","biostatistics methodology","comparative international policy","advanced robotics curricula","translational medicine research","sustainable materials engineering","computational social science","STEM pedagogy research","applied cryptography"],
  "Industry Professional": ["enterprise AI deployment","clean energy project finance","product management for health tech","supply chain digitization","industrial automation","cloud infrastructure strategy","fintech innovation","talent development programs","regulatory affairs","venture-backed hardware startups"]
};
const goalPools = {
  "Undergraduate Student": ["secure a research internship","publish a first co-authored paper","build a portfolio for graduate applications","find a mentor in the field","join a student research lab"],
  "Master's Student": ["complete a thesis with real-world impact","transition into a PhD program","present at a major conference","build an industry network","co-author a journal submission"],
  "PhD Researcher": ["finish the dissertation and defend within two years","publish in top-tier venues","secure postdoctoral funding","build a multidisciplinary collaboration","present a keynote at a conference"],
  "Professor": ["secure major grant funding","grow a research lab","mentor the next generation of researchers","influence policy through research","expand international collaborations"],
  "Industry Professional": ["bridge research and applied deployment","mentor early-career researchers","find research partners for R&D projects","stay current with academic advances","contribute to standards and policy discussions"]
};
const motivationPools = {
  "Undergraduate Student": "wants early exposure to a professional research community and mentorship",
  "Master's Student": "is looking for thesis collaborators and a pathway into doctoral research",
  "PhD Researcher": "wants visibility for ongoing research and connections to funding and collaborators",
  "Professor": "wants to expand institutional reach and find collaborators for grant-funded projects",
  "Industry Professional": "wants to stay connected to academic research and find talent and partnership opportunities"
};

const members = [];
let idx = 0;
for (const block of levelBlocks) {
  for (let i = 0; i < 10; i++) {
    const name = names[idx];
    const country = countries[idx];
    const interests = interestPools[block.level];
    const goals = goalPools[block.level];
    const interest1 = interests[i % interests.length];
    const interest2 = interests[(i + 3) % interests.length];
    const goal = goals[i % goals.length];
    members.push({
      member_id: 'IAASSE-' + String(idx + 1).padStart(3, '0'),
      name: name,
      country: country,
      academic_level: block.level,
      research_interests: interest1 + '; ' + interest2,
      biography: name + ' is a ' + block.level.toLowerCase() + ' based in ' + country + ' with a focus on ' + interest1 + '. Over the past few years they have built experience applying these methods to real-world problems and are now looking to deepen their involvement with the global research community.',
      career_goals: goal,
      motivation_for_joining: motivationPools[block.level],
      group: ['A','B','C'][idx % 3]
    });
    idx++;
  }
}
return members.map(m => ({ json: m }));

function extractJsonText(raw) {
  if (raw == null) return '';
  if (typeof raw === 'string') return raw;
  if (Array.isArray(raw)) {
    return raw.map(p => (typeof p === 'string' ? p : ((p && (p.text ?? p.content)) || ''))).join('\n');
  }
  if (typeof raw === 'object') {
    return raw.text ?? raw.content ?? raw.output_text ?? raw.output ?? JSON.stringify(raw);
  }
  return String(raw);
}
function safeParseJson(text) {
  if (!text) return null;
  let cleaned = String(text).trim();
  cleaned = cleaned.replace(/^```(json)?/i, '').replace(/```$/, '').trim();
  const start = cleaned.indexOf('{');
  const end = cleaned.lastIndexOf('}');
  if (start >= 0 && end > start) cleaned = cleaned.slice(start, end + 1);
  try { return JSON.parse(cleaned); } catch (e) { return null; }
}

const allowedSegments = ["Research Enthusiast","Publication Focused","Conference Seeker","Networking Focused","Volunteer Candidate","Leadership Candidate","Passive Member"];
const allowedAreas = ["Conference Participation","Journal Submission","Research Collaboration","Volunteer Program","Committee Membership","Industry Networking","Student Mentorship"];

return $input.all().map(item => {
  const j = item.json || {};
  const rawCandidate = j.content ?? j.text ?? j.output ?? j.message ?? j;
  const text = extractJsonText(rawCandidate);
  const parsed = safeParseJson(text);

  const base = {
    member_id: j.member_id, name: j.name, country: j.country, academic_level: j.academic_level,
    research_interests: j.research_interests, biography: j.biography, career_goals: j.career_goals,
    motivation_for_joining: j.motivation_for_joining, group: j.group
  };

  if (!parsed) {
    return { json: { ...base,
      engagement_score: 50, open_probability: 50, reply_probability: 30,
      conference_attendance_probability: 30, publication_probability: 30, volunteer_probability: 30,
      long_term_membership_probability: 30, segment: 'Passive Member', segment_confidence: 0,
      top_recommendation_area: 'Conference Participation', recommendations_json: '[]',
      reasoning_notes: 'Scoring call failed or returned invalid JSON; default neutral scores applied.',
      score_parse_error: true
    }};
  }

  const recs = Array.isArray(parsed.recommendations) ? parsed.recommendations.filter(r => r && allowedAreas.includes(r.area)) : [];
  const sortedRecs = [...recs].sort((a,b) => (Number(b.relevance_score)||0) - (Number(a.relevance_score)||0));
  const top = sortedRecs[0] || { area: 'Conference Participation', relevance_score: 0, explanation: '' };
  const reasoningParts = [parsed.engagement_score_reasoning, parsed.open_probability_reasoning, parsed.reply_probability_reasoning].filter(Boolean);

  return { json: { ...base,
    engagement_score: Number(parsed.engagement_score) || 0,
    open_probability: Number(parsed.open_probability) || 0,
    reply_probability: Number(parsed.reply_probability) || 0,
    conference_attendance_probability: Number(parsed.conference_attendance_probability) || 0,
    publication_probability: Number(parsed.publication_probability) || 0,
    volunteer_probability: Number(parsed.volunteer_probability) || 0,
    long_term_membership_probability: Number(parsed.long_term_membership_probability) || 0,
    segment: allowedSegments.includes(parsed.segment) ? parsed.segment : 'Passive Member',
    segment_confidence: Number(parsed.segment_confidence) || 0,
    top_recommendation_area: top.area,
    recommendations_json: JSON.stringify(sortedRecs),
    reasoning_notes: reasoningParts.join(' | '),
    score_parse_error: false
  }};
});

