      email_body: 'We were unable to generate a personalized message for this member; please review manually.',
      cta: '', recommended_opportunity: '', email_parse_error: true } };
  }
  return { json: { ...j, variant_type: 'personalized', email_subject: parsed.subject || 'An invitation from IAASSE',
    email_body: parsed.body || '', cta: '', recommended_opportunity: '', email_parse_error: false } };
