      cta: '', recommended_opportunity: j.top_recommendation_area || '', email_parse_error: true } };
  }
  return { json: { ...j, variant_type: 'optimized', email_subject: parsed.subject || 'An invitation from IAASSE',
    email_body: parsed.body || '', cta: parsed.cta || '', recommended_opportunity: parsed.recommended_opportunity || (j.top_recommendation_area || ''), email_parse_error: false } };
});

const items = $input.first().json.data || [];
const groups = ['A','B','C'];
const groupStats = {};
function avg(list, key) { if (!list.length) return 0; return list.reduce((s,m)=>s+(Number(m[key])||0),0)/list.length; }
function round1(n) { return Math.round(n*10)/10; }

for (const g of groups) {
  const members = items.filter(m => m.group === g);
  groupStats[g] = {
    group: g,
    sample_size: members.length,
    avg_open_probability: round1(avg(members,'open_probability')),
    avg_reply_probability: round1(avg(members,'reply_probability')),
    avg_engagement_score: round1(avg(members,'engagement_score')),
    avg_conference_probability: round1(avg(members,'conference_attendance_probability')),
    avg_publication_probability: round1(avg(members,'publication_probability')),
    avg_volunteer_probability: round1(avg(members,'volunteer_probability')),
    avg_long_term_probability: round1(avg(members,'long_term_membership_probability'))
  };
}
function pct(base, value) { if (!base) return 0; return round1(((value-base)/base)*100); }
const control = groupStats['A'];
for (const g of groups) {
  groupStats[g].pct_improvement_open_vs_control = pct(control.avg_open_probability, groupStats[g].avg_open_probability);
  groupStats[g].pct_improvement_engagement_vs_control = pct(control.avg_engagement_score, groupStats[g].avg_engagement_score);
}

const segmentCounts = {};
for (const m of items) { segmentCounts[m.segment] = (segmentCounts[m.segment]||0) + 1; }
const bestVariant = groups.slice().sort((a,b)=>groupStats[b].avg_open_probability - groupStats[a].avg_open_probability)[0];
const segmentEntries = Object.entries(segmentCounts).sort((a,b)=>b[1]-a[1]);
const bestSegment = segmentEntries.length ? segmentEntries[0][0] : 'Unknown';

const overall = {
  total_members: items.length,
  avg_open_probability: round1(avg(items,'open_probability')),
  avg_reply_probability: round1(avg(items,'reply_probability')),
  avg_engagement_score: round1(avg(items,'engagement_score')),
  avg_long_term_probability: round1(avg(items,'long_term_membership_probability')),
  best_performing_variant: bestVariant,
  best_performing_segment: bestSegment,
  segment_distribution: segmentCounts
};

return [{ json: { groupResults: [groupStats['A'], groupStats['B'], groupStats['C']], overall } }];

