const metricsItem = $('Compute A/B/C Test Metrics').first().json;
const j = $input.first().json || {};
const rawCandidate = j.content ?? j.text ?? j.output ?? j.message;
const text = extractJsonText(rawCandidate);
const parsed = safeParseJson(text);
const insights = (parsed && Array.isArray(parsed.insights)) ? parsed.insights.filter(i => i && i.finding) : [];
return [{ json: {
  groupResults: metricsItem.groupResults,
  overall: metricsItem.overall,
  insights: insights.length ? insights : [{ category: 'Notice', finding: 'AI insight generation failed or returned invalid JSON.', recommendation: 'Re-run the Generate AI Insights step.' }]
} }];

const o = ($input.first().json || {}).overall || {};
const rows = [
  { metric_name: 'Total Members', metric_value: String(o.total_members) },
  { metric_name: 'Average Open Probability (%)', metric_value: String(o.avg_open_probability) },
  { metric_name: 'Average Reply Probability (%)', metric_value: String(o.avg_reply_probability) },
  { metric_name: 'Average Engagement Score', metric_value: String(o.avg_engagement_score) },
  { metric_name: 'Average Long-Term Membership Probability (%)', metric_value: String(o.avg_long_term_probability) },
  { metric_name: 'Best Performing Outreach Variant', metric_value: String(o.best_performing_variant) },
  { metric_name: 'Best Performing Segment', metric_value: String(o.best_performing_segment) },
  { metric_name: 'Segment Distribution', metric_value: JSON.stringify(o.segment_distribution || {}) },
  { metric_name: 'Report Generated At', metric_value: new Date().toISOString() }
];
return rows.map(r => ({ json: r }));

